import { Fragment } from 'react';
import { Helmet } from 'react-helmet';
import Image from 'components/Image';
import { useScrollRestore } from 'hooks';
import Footer from 'components/Footer';
import {
  ProjectContainer,
  ProjectSection,
  ProjectSectionContent,
  ProjectImage,
  ProjectTextRow,
  ProjectSectionHeading,
  ProjectSectionText,
  ProjectBackground,
  ProjectHeader,
  ProjectSectionColumns,
} from 'components/ProjectLayout';
import sliceBackground from 'assets/d3data.jpg';
import sliceBackgroundLarge from 'assets/d3data.jpg';
import sliceBackgroundPlaceholder from 'assets/slice-background-placeholder.jpg';
import sliceApp from 'assets/d3data.jpg';
import sliceAppLarge from 'assets/d3data.jpg';
import sliceAppPlaceholder from 'assets/slice-app-placeholder.jpg';
import sliceSidebarLayers from 'assets/slice-sidebar-layers.png';
import sliceSidebarLayersLarge from 'assets/stoloto2.png';
import sliceSidebarLayersPlaceholder from 'assets/slice-sidebar-layers-placeholder.png';
import sliceSidebarAnnotations from 'assets/slice-sidebar-annotations.png';
import sliceSidebarAnnotationsLarge from 'assets/stoloto1.png';
import sliceSidebarAnnotationsPlaceholder from 'assets/slice-sidebar-annotations-placeholder.png';
import stolotoThree from 'assets/three-stoloto.jpg';
import stolotoThreeLarge from 'assets/three-stoloto.jpg';
import sliceSlidesPlaceholder from 'assets/slice-slides-placeholder.jpg';
import zodiakLarge from 'assets/zodiak.png';
import prerender from 'utils/prerender';
import { media } from 'utils/style';
import './index.css';

const title = 'Корпоративная шина данных, высоконагруженный сайт';
const description =
  'Ключевые проекты компании. Шина гарантировала доставку данных, сайт stoloto приносил основую прибыль компании.';
const roles = ['Frontend разработка', 'UX дизайн', 'UI дизайн'];

const ProjectSlice = () => {
  useScrollRestore();

  return (
    <Fragment>
      <Helmet>
        <title>{`Projects | ${title}`}</title>
        <meta name="description" content={description} />
      </Helmet>
      <ProjectContainer className="slice">
        <ProjectBackground
          srcSet={`${sliceBackground} 1280w, ${sliceBackgroundLarge} 2560w`}
          placeholder={sliceBackgroundPlaceholder}
          opacity={0.8}
          entered={!prerender}
        />
        <ProjectHeader
          title={title}
          description={description}
          url="https://www.stoloto.ru/?int=sitemap"
          roles={roles}
        />
        <ProjectSection first>
          <ProjectSectionContent>
            <ProjectImage
              srcSet={`${sliceApp} 800w, ${sliceAppLarge} 1920w`}
              placeholder={sliceAppPlaceholder}
              alt="The Slice web application showing a selected user annotation."
              sizes={`(max-width: ${media.mobile}px) 100vw, (max-width: ${media.tablet}px) 90vw, 80vw`}
            />
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection>
          <ProjectSectionColumns centered className="slice__columns">
            <div className="sidebar__images-text">
              <ProjectSectionHeading>Доставка данных</ProjectSectionHeading>
              <ProjectSectionText>
                Корпоративная шина данных - ключевой проект компании. Она пронизывала всю систему словно сосуды и позволяла гарантированно доставлять данные из всех контейнеров и окружений компании.
              </ProjectSectionText>
              <ProjectSectionText>
                Максимальный выигрыш в лотерею - 1 миллиард рублей. Именно такая цифра потенциально могла стать ценой ошибки доставки данных.
              </ProjectSectionText>
            </div>
            <div className="slice__sidebar-images">
              <Image
                className="slice__sidebar-image"
                srcSet={`${sliceSidebarLayers} 300w, ${sliceSidebarLayersLarge} 700w`}
                placeholder={sliceSidebarLayersPlaceholder}
                alt="The layers sidebar design, now with user profiles."
                sizes={`(max-width: ${media.mobile}px) 200px, 343px`}
              />
              <Image
                className="slice__sidebar-image"
                srcSet={`${sliceSidebarAnnotations} 300w, ${sliceSidebarAnnotationsLarge} 700w`}
                placeholder={sliceSidebarAnnotationsPlaceholder}
                alt="Multiple user annotations on a shared layer."
                sizes={`(max-width: ${media.mobile}px) 200px, 343px`}
              />
            </div>
          </ProjectSectionColumns>
        </ProjectSection>
        <ProjectSection light>
          <ProjectSectionContent>
            <ProjectTextRow>
              <ProjectSectionHeading>Задачи</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>Разработка/доработка функционала ключевого проекта компании: корпоративной шины данных</li>
                  <li>Переписывание на современных стек и поддержка старого высоко нагруженного сайта stoloto.ru</li>
                  <li>Переписывание внутренних проектов на современный стек</li>
                  <li>Разработка экспериментального проекта</li>
                  <li>Работа над сложным графиком обработки данных в реальном времени</li>
                  <li>Разработка/Поддержка административных панелей</li>
                  <li>Разработка сайта 888.ru</li>
                  <li>Разработка "витрин" со сложной анимацией и доработка движка</li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
            <Image
              srcSet={`${stolotoThree} 800w, ${stolotoThreeLarge} 1440w`}
              placeholder={sliceSlidesPlaceholder}
              alt="The new My Slides tab in slice, showing annotated and favorited slides."
              sizes={`(max-width: ${media.mobile}px) 500px, (max-width: ${media.tablet}px) 800px, 1000px`}
            />
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection light>
          <ProjectSectionContent>
            <ProjectTextRow>
              <ProjectSectionHeading>Достижения</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>Быстро вошёл в проект и овладел технологией, что позволило выправить процесс релизов</li>
                  <li>Успешно заменял руководителя отдела в его отпуск</li>
                  <li>В одиночку разрабатывал и вёл переговоры по экспериментальному проекту портативной витрины</li>
                  <li>Успешно делегировал задачи (по уровню сложности и приоритету) между несколькими членами команды в рамках некоторых проектов. Что позволило прокачать их умения и не выйти за установленные рамки релиза</li>
                  <li>Совместно с тех. лидом заложил архитектуру/каркас проектов, которые впоследствии были переписаны на современных стек</li>
                  <li>Получил повышение до Ведущего разработчика</li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
            <Image
              srcSet={`${zodiakLarge} 800w, ${zodiakLarge} 1440w`}
              placeholder={sliceSlidesPlaceholder}
              alt="The new My Slides tab in slice, showing annotated and favorited slides."
              sizes={`(max-width: ${media.mobile}px) 500px, (max-width: ${media.tablet}px) 800px, 1000px`}
            />
          </ProjectSectionContent>
        </ProjectSection>
      </ProjectContainer>
      <Footer />
    </Fragment>
  );
};

export default ProjectSlice;
